// ─── Proof layout (256 bytes) ─────────────────────────────────────────────────
//   bytes   0.. 64  proof_a: G1 point (-A, negated), big-endian uncompressed
//   bytes  64..192  proof_b: G2 point ( B),          big-endian uncompressed
//   bytes 192..256  proof_c: G1 point ( C),          big-endian uncompressed

/// Verify a Groth16 proof for the Withdraw circuit.
///
/// `proof`         — 256-byte packed proof (proof_a_neg || proof_b || proof_c).
/// `public_inputs` — [root, nullifier_hash, recipient_bytes] each 32 bytes BE.
pub fn verify_withdraw_proof(
    proof: &[u8; 256],
    public_inputs: &[[u8; 32]; 3],
) -> Result<()> {
    let proof_a: &[u8; 64]  = proof[0..64].try_into().unwrap();
    let proof_b: &[u8; 128] = proof[64..192].try_into().unwrap();
    let proof_c: &[u8; 64]  = proof[192..256].try_into().unwrap();

    let mut verifier = Groth16Verifier::new(
        proof_a,
        proof_b,
        proof_c,
        public_inputs,
        &WITHDRAW_VK,
    )
    .map_err(|_| error!(NaraZkError::InvalidProof))?;

    verifier
        .verify()
        .map_err(|_| error!(NaraZkError::InvalidProof))?;

    Ok(())
}

/// Verify a Groth16 proof for the OwnershipProof circuit.
///
/// `proof`         — 256-byte packed proof.
/// `id_commitment` — current on-chain id_commitment (the single public input).
pub fn verify_ownership_proof(
    proof: &[u8; 256],
    id_commitment: &[u8; 32],
) -> Result<()> {
    let proof_a: &[u8; 64]  = proof[0..64].try_into().unwrap();
    let proof_b: &[u8; 128] = proof[64..192].try_into().unwrap();
    let proof_c: &[u8; 64]  = proof[192..256].try_into().unwrap();

    let public_inputs: &[[u8; 32]; 1] = std::slice::from_ref(id_commitment)
        .try_into()
        .unwrap();

    let mut verifier = Groth16Verifier::new(
        proof_a,
        proof_b,
        proof_c,
        public_inputs,
        &OWNERSHIP_VK,
    )
    .map_err(|_| error!(NaraZkError::InvalidProof))?;

    verifier
        .verify()
        .map_err(|_| error!(NaraZkError::InvalidProof))?;

    Ok(())
}
